let currentIndex = 0;
function setCurrentIndex(slide) {
    console.log(slide)
    switch(slide) {
        case "dnd":
            currentIndex = 1;
            break;
        case "paperboy":
            currentIndex = 2;
            break;
        default:
            currentIndex = 0;
            break;
    }
}

function setActiveButton() {
    [availoButton, dndButton, pbButton].forEach(btn => btn.classList.remove("active"));
    
    if (currentIndex === 0) availoButton.classList.add("active");
    else if (currentIndex === 1) dndButton.classList.add("active");
    else pbButton.classList.add("active");
}

function setSlideContent() {
    const slide = slides[currentIndex];
    title.textContent = slide.title;
    tag.textContent = slide.tag;
    // New image(s)
    imageContainer.innerHTML = "";
    if (slide.svg) {
        imageContainer.innerHTML = slide.svg;
    } else {
        slide.images.forEach(image => {
            const img = document.createElement("img");
            img.id = image.id;
            img.src = image.src;
            img.alt = image.alt ?? "";
            imageContainer.appendChild(img);
        });
    }
    // New Description
    description.innerHTML = "";
    slide.paragraphs.forEach(textBlock => {
        const p = document.createElement("p");
        p.innerText = textBlock;
        description.appendChild(p);
    });
    // New link
    if (slide.linkType) {
        const newLink = document.createElement("a");
        newLink.dataset.linkType = slide.linkType;
        newLink.href = slide.linkHref;
        newLink.textContent = slide.linkText;
        link.replaceWith(newLink);
        link = newLink;
    }
    // New Tools
    tools.innerHTML = "";
    slide.tools.forEach(tool => {
        const span = document.createElement("span");
        span.innerText = tool;
        tools.appendChild(span);
    });
}

function slideTransition(animation, callback) {
    const slideFadeDuration = 0.6;
    const mediaContainer = document.querySelector("#projects .project .media");
    const imageContainer = document.querySelector("#projects .project .media .image");
    const contentElement = document.querySelector("#projects .project .content");

    const tl = gsap.timeline({ onComplete: callback });

    if (animation === "close") {
        tl.to(contentElement, { duration: slideFadeDuration, opacity: 0, x: "0px" })
            .to(imageContainer, { duration: slideFadeDuration, maxWidth: "0%" }, "<")
            .to(mediaContainer, { duration: slideFadeDuration, opacity: 0 }, "<");
    } else {
        tl.to(mediaContainer, { duration: slideFadeDuration, opacity: 1 })
            .to(imageContainer, { duration: slideFadeDuration, maxWidth: "100%" }, "<")
            .to(contentElement, { duration: slideFadeDuration, opacity: 1, x: "0px" }, "<")
    }
}

function goToSlide(slide) {
    if (
        (slide === "availo" && currentIndex === 0)
        || (slide === "paperboy" && currentIndex === 2)
    ) {
        return;
    }
    setCurrentIndex(slide);
    setActiveButton()
    slideTransition("close", () => {
        setSlideContent();
        slideTransition("open");
    });
}

[availoButton, dndButton, pbButton].forEach(btn => {
    const slide = btn.dataset.slide;
    btn.addEventListener("click", () => goToSlide(slide));
});